export const MIGRATIONS = [
  { name: "0001_init.sql", sql: `-- Users: one row per account.
-- password_hash format: "pbkdf2$<iters>$<salt_b64>$<hash_b64>"
CREATE TABLE users (
  id          TEXT PRIMARY KEY,
  email       TEXT NOT NULL UNIQUE,
  display_name TEXT NOT NULL,
  password_hash TEXT NOT NULL,
  created_at  INTEGER NOT NULL,
  last_login_at INTEGER
);

CREATE INDEX idx_users_email ON users(LOWER(email));

-- Sessions: opaque token -> user. Token is the cookie value (random 32 bytes, base64url).
CREATE TABLE sessions (
  token       TEXT PRIMARY KEY,
  user_id     TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  created_at  INTEGER NOT NULL,
  expires_at  INTEGER NOT NULL,
  user_agent  TEXT
);

CREATE INDEX idx_sessions_user ON sessions(user_id);
CREATE INDEX idx_sessions_expires ON sessions(expires_at);
` },
  { name: "0002_rooms.sql", sql: `-- Rooms: a lobby record for each game session. The live state lives in a Durable Object
-- keyed by room.id; this table is the index for discovery / cross-user queries.
CREATE TABLE rooms (
  id          TEXT PRIMARY KEY,
  name        TEXT NOT NULL,
  host_id     TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  status      TEXT NOT NULL DEFAULT 'lobby',  -- 'lobby' | 'in_progress' | 'closed'
  max_players INTEGER NOT NULL DEFAULT 4,
  created_at  INTEGER NOT NULL,
  updated_at  INTEGER NOT NULL
);

CREATE INDEX idx_rooms_status ON rooms(status, updated_at DESC);

-- Memberships: who has joined which room. The DO is the source of truth for who's
-- currently connected; this table records the intent ("I have a seat in this room").
CREATE TABLE room_members (
  room_id   TEXT NOT NULL REFERENCES rooms(id) ON DELETE CASCADE,
  user_id   TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  joined_at INTEGER NOT NULL,
  PRIMARY KEY (room_id, user_id)
);

CREATE INDEX idx_members_user ON room_members(user_id);
` },
  { name: "0003_game_state.sql", sql: `-- ============================================================================
-- Orbital — Game State Schema (v1, alpha-target)
-- ============================================================================
--
-- This migration adds the per-match game state on top of the existing
-- accounts (0001) and lobby/room (0002) layers. It targets the asynchronous
-- daily-tick strategy game described in design doc v0.3.
--
-- KEY MODELING DECISIONS (read first):
--
--   1. Room vs. game. A \`rooms\` row (from 0002) is a lobby seat plan; when
--      the host starts the match, a \`games\` row is created with id == room id.
--      The room continues to exist so the lobby can show finished matches
--      and so post-game chronicle viewing has a stable join target.
--
--   2. Game-room as the tenancy boundary. Every gameplay row carries
--      \`game_id\` and almost every query is scoped by it. The \`Room\` Durable
--      Object owns the live working copy of state and writes through to D1
--      on tick commit; D1 is the source of truth for everything that
--      survives DO eviction.
--
--   3. Factions are first-class. A player joins a game by claiming exactly
--      one faction (1:1 user<->faction within a game). A faction can also be
--      AI-controlled (user_id NULL) or vacated/eliminated. Faction id is
--      the identity used by every other gameplay row (ownership, treaties,
--      senate votes, message authorship). Do NOT key gameplay rows on
--      user_id directly — that breaks AI/observer cases.
--
--   4. Per-game bodies. Bodies are not global seed data. They are copied
--      into \`game_bodies\` at game start so variant maps are possible and
--      so per-game state (ownership, development, resources) lives on the
--      same row that defines orbital geometry.
--
--   5. Keplerian orbits. Both bodies and ships store orbits as classical
--      elements (rp, ra, omega, M0, epoch, direction). This matches the
--      current prototype's patched-conics sim. If the engine ever moves to
--      RK4 N-body, add \`state_vector_*\` columns rather than restructuring.
--
--   6. Sensor visibility as stored projection. \`sensor_coverage\` materializes
--      "faction F can see body B at level L" so reads of bodies/ships can
--      be filtered with a single join. The tick processor recomputes this
--      table at the end of each tick.
--
--   7. Per-tick snapshots. \`game_snapshots\` stores a JSON dump of derived
--      state per tick for rollback and for the chronicle viewer. Authoritative
--      *live* state is the relational tables, not the snapshot blob.
--
--   8. Order intent. Most "orders" are state mutations directly visible on
--      domain rows (e.g. node.committed = 1, faction.research_queue, ship
--      build queue rows). The generic \`pending_orders\` table is for
--      cross-cutting actions that don't fit a single domain table
--      (e.g. sigint scans, signed declarations queued for tick boundary).
--
--   9. Reserved-for-v2 tables. \`standing_orders\` is defined here even
--      though v1 alpha won't implement the if-then engine, so the v2
--      migration is additive (no rename/restructure). Similarly,
--      \`messages.claimed_sender_faction_id\` is reserved so the v2 forgery
--      mechanic doesn't require a column rename.
--
--   10. Time. The unit of game time is \`tick_number\` (0-indexed). Wall-clock
--       timestamps are stored as INTEGER ms since epoch. Never confuse the
--       two: gameplay logic operates in ticks; the scheduler operates in ms.
--
-- ============================================================================
-- SECTION 1 — Games, ticks, factions, players
-- ============================================================================

-- One row per started match. The room (0002) is the lobby; a game is the
-- match itself. game.id == room.id so post-game viewing can join either way.
CREATE TABLE games (
  id                  TEXT PRIMARY KEY REFERENCES rooms(id) ON DELETE CASCADE,
  status              TEXT NOT NULL DEFAULT 'setup',
    -- 'setup'      : host is configuring map/factions, lobby open
    -- 'active'     : ticks are running
    -- 'completed'  : a victory condition triggered; chronicle finalized
    -- 'abandoned'  : host or system ended without a victor
  victory_type        TEXT,                -- NULL until completed; 'hegemony'|'political'|'last_standing'|'secret'|'abandoned'
  winner_faction_id   TEXT,                -- FK declared below (circular; enforced via trigger if needed)
  map_seed            TEXT NOT NULL,       -- deterministic body-generation seed; allows reproducibility
  current_tick        INTEGER NOT NULL DEFAULT 0,
  -- Match length and cadence. The schema defaults below are historical
  -- (the 0003 migration shipped with a 42-tick / 24h-per-tick "one move
  -- per day" design); the live defaults are now supplied explicitly by
  -- worker/lobby.js (DEFAULT_TOTAL_TICK_TARGET=4000,
  -- DEFAULT_TICK_INTERVAL_MS=450_000) so every newly-created match uses
  -- the current pace: 7.5 min/tick × 4000 ticks ≈ a 21-day game with
  -- Earth→Jupiter transits ≈ 1.5 real days. See DESIGN.md "Time and
  -- pacing" for the rationale.
  total_tick_target   INTEGER NOT NULL DEFAULT 4000,     -- design pace: 3-week match
  tick_interval_ms    INTEGER NOT NULL DEFAULT 450000,   -- 7.5 min/tick; lobby.js may override
  next_tick_at        INTEGER,             -- scheduled wall-clock ms; NULL while paused/setup
  senate_period_ticks INTEGER NOT NULL DEFAULT 7,
  created_at          INTEGER NOT NULL,
  started_at          INTEGER,
  completed_at        INTEGER
);

CREATE INDEX idx_games_status_next ON games(status, next_tick_at);

-- Tick log. One row per executed (or scheduled) tick. The tick processor
-- inserts a row with status='scheduled', flips it to 'processing' while
-- running, and 'completed' on success. Provides a join target for events.
CREATE TABLE game_ticks (
  game_id        TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  tick_number    INTEGER NOT NULL,
  status         TEXT NOT NULL DEFAULT 'scheduled',  -- 'scheduled'|'processing'|'completed'|'failed'
  scheduled_at   INTEGER NOT NULL,
  started_at     INTEGER,
  completed_at   INTEGER,
  error          TEXT,
  PRIMARY KEY (game_id, tick_number)
);

CREATE INDEX idx_ticks_schedule ON game_ticks(status, scheduled_at);

-- A faction is a seat in a specific game. Bound to a user (or AI) and a
-- capital body (loss-of-capital = elimination per design). The four
-- resource columns are the per-faction stockpile.
CREATE TABLE game_factions (
  id                 TEXT PRIMARY KEY,
  game_id            TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  user_id            TEXT REFERENCES users(id) ON DELETE SET NULL,  -- NULL = AI or vacated seat
  slot              INTEGER NOT NULL,            -- 0..N-1, stable seat number for UI ordering
  name              TEXT NOT NULL,               -- in-game faction name (e.g. "Verdan Concord")
  color             TEXT NOT NULL,               -- hex; used by renderer + chronicle
  status            TEXT NOT NULL DEFAULT 'active',  -- 'active'|'eliminated'|'observer'|'vacated'
  capital_body_id   TEXT,                        -- FK to game_bodies(id); set at game start
  reputation        INTEGER NOT NULL DEFAULT 0,
  senate_weight     INTEGER NOT NULL DEFAULT 1,  -- recomputed each tick; observers = 0.5 (stored *2 if needed)
  metal             INTEGER NOT NULL DEFAULT 0,
  fuel              INTEGER NOT NULL DEFAULT 0,
  gold              INTEGER NOT NULL DEFAULT 0,
  science           INTEGER NOT NULL DEFAULT 0,
  research_tech_id  TEXT,                        -- currently-researching tech; NULL = idle
  research_progress INTEGER NOT NULL DEFAULT 0,  -- science accumulated toward research_tech_id
  joined_at         INTEGER NOT NULL,
  eliminated_at_tick INTEGER,
  UNIQUE (game_id, slot),
  UNIQUE (game_id, user_id)                      -- a user can only hold one seat per game
);

CREATE INDEX idx_factions_game ON game_factions(game_id);
CREATE INDEX idx_factions_user ON game_factions(user_id);

-- ============================================================================
-- SECTION 2 — Bodies (per-game) and ownership
-- ============================================================================

-- Bodies are per-game so variant maps and dynamic per-body state share a row.
-- Geometry columns mirror the prototype's BODIES[] entries. Resource yield
-- columns are the per-tick production from this body when developed.
CREATE TABLE game_bodies (
  id              TEXT PRIMARY KEY,
  game_id         TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  template_id     TEXT NOT NULL,            -- references seed catalog in code (e.g. 'sol','inara'); not a FK
  name            TEXT NOT NULL,
  type            TEXT NOT NULL,            -- 'star'|'terrestrial'|'gas-giant'|'moon'|'asteroid'|'lagrange'
  parent_body_id  TEXT REFERENCES game_bodies(id),   -- NULL for the system primary
  radius          REAL NOT NULL,            -- physical radius (sim units)
  soi             REAL,                     -- sphere of influence radius; NULL for the star
  mu              REAL NOT NULL,            -- gravitational parameter
  orbit_radius    REAL,                     -- semi-major axis around parent
  orbit_period    REAL,                     -- ticks or sim-time-units; defined by engine convention
  angle0          REAL,                     -- mean anomaly at epoch 0
  color           TEXT NOT NULL,
  -- per-tick base resource yield when fully developed (level 3); scaled by development_level
  yield_metal     INTEGER NOT NULL DEFAULT 0,
  yield_fuel      INTEGER NOT NULL DEFAULT 0,
  yield_gold      INTEGER NOT NULL DEFAULT 0,
  yield_science   INTEGER NOT NULL DEFAULT 0,
  -- per-game mutable state
  owner_faction_id    TEXT REFERENCES game_factions(id) ON DELETE SET NULL,
  development_level   INTEGER NOT NULL DEFAULT 0,    -- 0=unclaimed,1=claimed flag,2=outpost,3=developed base
  fortification_level INTEGER NOT NULL DEFAULT 0,
  shipyard_level      INTEGER NOT NULL DEFAULT 0,
  claimed_at_tick     INTEGER,
  developed_at_tick   INTEGER
);

CREATE INDEX idx_bodies_game ON game_bodies(game_id);
CREATE INDEX idx_bodies_owner ON game_bodies(owner_faction_id);
CREATE INDEX idx_bodies_parent ON game_bodies(parent_body_id);

-- Now that game_bodies exists, declare the deferred faction->capital FK
-- as an index-only contract (SQLite does not support late ADD CONSTRAINT;
-- the relationship is enforced in application code).
CREATE INDEX idx_factions_capital ON game_factions(capital_body_id);

-- Build queue on a body's shipyard. One row per ordered ship; consumed when
-- the tick processor completes construction.
CREATE TABLE game_body_build_queue (
  id                  TEXT PRIMARY KEY,
  game_id             TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  body_id             TEXT NOT NULL REFERENCES game_bodies(id) ON DELETE CASCADE,
  faction_id          TEXT NOT NULL REFERENCES game_factions(id) ON DELETE CASCADE,
  ship_class          TEXT NOT NULL,        -- 'frigate'|'cruiser'|'capital'|'stealth'
  queued_at_tick      INTEGER NOT NULL,
  completes_at_tick   INTEGER NOT NULL,
  cancelled_at_tick   INTEGER
);

CREATE INDEX idx_build_queue_completion ON game_body_build_queue(game_id, completes_at_tick)
  WHERE cancelled_at_tick IS NULL;

-- Body development queue (claim -> outpost -> developed). Similar shape;
-- separate table because development is independent of ship construction.
CREATE TABLE game_body_development (
  id                  TEXT PRIMARY KEY,
  game_id             TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  body_id             TEXT NOT NULL REFERENCES game_bodies(id) ON DELETE CASCADE,
  faction_id          TEXT NOT NULL REFERENCES game_factions(id) ON DELETE CASCADE,
  target_level        INTEGER NOT NULL,     -- 1, 2, or 3
  started_at_tick     INTEGER NOT NULL,
  completes_at_tick   INTEGER NOT NULL,
  cancelled_at_tick   INTEGER
);

CREATE INDEX idx_development_completion ON game_body_development(game_id, completes_at_tick)
  WHERE cancelled_at_tick IS NULL;

-- ============================================================================
-- SECTION 3 — Ships and maneuver nodes
-- ============================================================================

-- A ship lives in a parent body's SOI with a Keplerian orbit around it.
-- Orbits change discretely on burns; between burns the engine integrates
-- the analytical Kepler orbit.
CREATE TABLE game_ships (
  id              TEXT PRIMARY KEY,
  game_id         TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  owner_faction_id TEXT NOT NULL REFERENCES game_factions(id) ON DELETE CASCADE,
  name            TEXT NOT NULL,
  ship_class      TEXT NOT NULL,            -- 'frigate'|'cruiser'|'capital'|'stealth'
  parent_body_id  TEXT NOT NULL REFERENCES game_bodies(id) ON DELETE CASCADE,
  -- current orbit (around parent_body_id); updated whenever a node executes
  orbit_rp        REAL NOT NULL,
  orbit_ra        REAL NOT NULL,
  orbit_omega     REAL NOT NULL,            -- argument of periapsis (rad)
  orbit_m0        REAL NOT NULL,            -- mean anomaly at epoch
  orbit_epoch     REAL NOT NULL,            -- sim time at which m0 applies
  orbit_direction INTEGER NOT NULL DEFAULT 1, -- +1 prograde, -1 retrograde
  -- resources
  fuel            REAL NOT NULL,
  fuel_max        REAL NOT NULL,
  -- status
  status          TEXT NOT NULL DEFAULT 'active',  -- 'active'|'destroyed'|'mothballed'
  built_at_tick   INTEGER NOT NULL,
  destroyed_at_tick INTEGER
);

CREATE INDEX idx_ships_game ON game_ships(game_id);
CREATE INDEX idx_ships_owner ON game_ships(owner_faction_id);
CREATE INDEX idx_ships_parent ON game_ships(parent_body_id);

-- Maneuver nodes — the planned/committed/executed lifecycle for ship burns.
-- The renderer in the prototype already understands this exact shape.
CREATE TABLE game_ship_nodes (
  id              TEXT PRIMARY KEY,
  game_id         TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  ship_id         TEXT NOT NULL REFERENCES game_ships(id) ON DELETE CASCADE,
  sequence        INTEGER NOT NULL,         -- ordering within the ship's plan; 0,1,2...
  anchor_kind     TEXT NOT NULL,            -- 'periapsis'|'apoapsis'|'encounter'|'capture'|'exit'|'absolute'
  anchor_body_id  TEXT REFERENCES game_bodies(id),   -- the body the anchor is relative to, if applicable
  target_body_id  TEXT REFERENCES game_bodies(id),   -- destination body for transfer/capture nodes
  scheduled_t     REAL NOT NULL,            -- sim time at which the burn fires
  dv_prograde     REAL NOT NULL DEFAULT 0,
  dv_normal       REAL NOT NULL DEFAULT 0,
  dv_radial       REAL NOT NULL DEFAULT 0,
  fuel_cost       REAL NOT NULL,            -- precomputed; the source of truth for fuel accounting at execute
  status          TEXT NOT NULL DEFAULT 'planned', -- 'planned'|'committed'|'executed'|'cancelled'|'failed'
  committed_at_tick INTEGER,
  executed_at_tick  INTEGER,
  UNIQUE (ship_id, sequence)
);

CREATE INDEX idx_nodes_ship ON game_ship_nodes(ship_id, sequence);
CREATE INDEX idx_nodes_due  ON game_ship_nodes(game_id, status, scheduled_t);

-- ============================================================================
-- SECTION 4 — Sensors, visibility, intelligence
-- ============================================================================

-- Per-faction view of bodies. Recomputed by the tick processor. The renderer
-- joins ships/bodies to this for fog-of-war. Coverage levels:
--   0 = unknown          (faction has no info; body invisible in UI)
--   1 = ephemeris        (orbit known, no current ship traffic visible)
--   2 = patrol           (ships in this SOI visible; trajectories shown)
--   3 = full intel       (build queue + development visible too)
CREATE TABLE sensor_coverage (
  game_id     TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  faction_id  TEXT NOT NULL REFERENCES game_factions(id) ON DELETE CASCADE,
  body_id     TEXT NOT NULL REFERENCES game_bodies(id) ON DELETE CASCADE,
  level       INTEGER NOT NULL,
  updated_at_tick INTEGER NOT NULL,
  PRIMARY KEY (game_id, faction_id, body_id)
);

CREATE INDEX idx_sensor_faction ON sensor_coverage(faction_id, body_id);

-- Sigint records — generated when sensors detect *that* a message was sent,
-- without revealing content. v2 may extend with partial-decrypt fields.
CREATE TABLE sigint_events (
  id              TEXT PRIMARY KEY,
  game_id         TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  observer_faction_id TEXT NOT NULL REFERENCES game_factions(id) ON DELETE CASCADE,
  detected_at_tick INTEGER NOT NULL,
  source_body_id  TEXT REFERENCES game_bodies(id),
  dest_body_id    TEXT REFERENCES game_bodies(id),
  signal_kind     TEXT NOT NULL              -- 'transmission'|'broadcast'|'narrowbeam'
);

CREATE INDEX idx_sigint_observer ON sigint_events(observer_faction_id, detected_at_tick);

-- ============================================================================
-- SECTION 5 — Diplomacy: treaties + senate
-- ============================================================================

-- Treaties are public game objects with finite duration in ticks.
CREATE TABLE treaties (
  id              TEXT PRIMARY KEY,
  game_id         TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  kind            TEXT NOT NULL,            -- 'nap'|'defense_pact'|'trade'|'intel_share'|'demilitarization'
  status          TEXT NOT NULL DEFAULT 'proposed',  -- 'proposed'|'active'|'expired'|'broken'|'cancelled'
  proposed_at_tick INTEGER NOT NULL,
  signed_at_tick  INTEGER,
  expires_at_tick INTEGER,                  -- NULL = open-ended
  broken_at_tick  INTEGER,
  breaker_faction_id TEXT REFERENCES game_factions(id),
  terms           TEXT NOT NULL DEFAULT '{}'  -- JSON; e.g. tariff rates, demilitarized bodies
);

CREATE INDEX idx_treaties_game_status ON treaties(game_id, status);

-- M2M: signatories of a treaty. The treaty becomes 'active' once every
-- signatory row has signed_at_tick set.
CREATE TABLE treaty_signatories (
  treaty_id   TEXT NOT NULL REFERENCES treaties(id) ON DELETE CASCADE,
  faction_id  TEXT NOT NULL REFERENCES game_factions(id) ON DELETE CASCADE,
  signed_at_tick INTEGER,
  PRIMARY KEY (treaty_id, faction_id)
);

-- Senate proposals run weekly (every senate_period_ticks). Lifecycle:
-- proposed -> debating -> voting -> resolved.
CREATE TABLE senate_proposals (
  id                 TEXT PRIMARY KEY,
  game_id            TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  proposer_faction_id TEXT REFERENCES game_factions(id),  -- NULL for system-generated
  kind               TEXT NOT NULL,         -- 'trade'|'military'|'scientific'|'recognition'|'sanction'|'crisis'
  title              TEXT NOT NULL,
  summary            TEXT NOT NULL,
  payload            TEXT NOT NULL DEFAULT '{}',  -- JSON; structure depends on kind
  status             TEXT NOT NULL DEFAULT 'debating', -- 'debating'|'voting'|'passed'|'failed'|'withdrawn'
  proposed_at_tick   INTEGER NOT NULL,
  vote_opens_at_tick INTEGER NOT NULL,
  vote_closes_at_tick INTEGER NOT NULL,
  resolved_at_tick   INTEGER,
  -- if passed, the modifier applies for the design-doc default of 7 ticks
  effect_until_tick  INTEGER
);

CREATE INDEX idx_senate_status ON senate_proposals(game_id, status, vote_closes_at_tick);

CREATE TABLE senate_votes (
  proposal_id TEXT NOT NULL REFERENCES senate_proposals(id) ON DELETE CASCADE,
  faction_id  TEXT NOT NULL REFERENCES game_factions(id) ON DELETE CASCADE,
  vote        TEXT NOT NULL,                -- 'yea'|'nay'|'abstain'
  weight      INTEGER NOT NULL,             -- snapshot of senate_weight at vote time
  cast_at_tick INTEGER NOT NULL,
  PRIMARY KEY (proposal_id, faction_id)
);

-- ============================================================================
-- SECTION 6 — Technology
-- ============================================================================

-- Per-faction tech progress. The tech catalog itself (ids, costs, branches,
-- prerequisites) lives in worker code as static seed data. This table just
-- records what each faction has unlocked.
CREATE TABLE faction_techs (
  game_id     TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  faction_id  TEXT NOT NULL REFERENCES game_factions(id) ON DELETE CASCADE,
  tech_id     TEXT NOT NULL,                -- e.g. 'prop.high_isp', 'sensors.deep_array'
  status      TEXT NOT NULL,                -- 'researching'|'completed'
  started_at_tick   INTEGER NOT NULL,
  completed_at_tick INTEGER,
  PRIMARY KEY (game_id, faction_id, tech_id)
);

CREATE INDEX idx_faction_techs_status ON faction_techs(game_id, faction_id, status);

-- ============================================================================
-- SECTION 7 — Messages and chronicle
-- ============================================================================

-- Messages are faction-to-faction (or broadcast). A signed message carries
-- the cryptographic guarantee that the named sender produced it. v2 forgery
-- introduces a distinction between claimed and actual sender; for v1 the
-- two columns hold the same value but exist now to avoid migration churn.
CREATE TABLE messages (
  id                 TEXT PRIMARY KEY,
  game_id            TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  actual_sender_faction_id  TEXT NOT NULL REFERENCES game_factions(id) ON DELETE CASCADE,
  claimed_sender_faction_id TEXT NOT NULL REFERENCES game_factions(id) ON DELETE CASCADE,
  scope              TEXT NOT NULL,         -- 'dm'|'group'|'broadcast'
  body               TEXT NOT NULL,
  signed             INTEGER NOT NULL DEFAULT 0,  -- 0/1; if 1, signature verifiable from public state
  sent_at_tick       INTEGER NOT NULL,
  sent_at_ms         INTEGER NOT NULL
);

CREATE INDEX idx_messages_game_tick ON messages(game_id, sent_at_tick DESC);

-- Recipients for dm/group; for broadcast, no rows are inserted and the
-- message is visible to every faction by virtue of scope.
CREATE TABLE message_recipients (
  message_id  TEXT NOT NULL REFERENCES messages(id) ON DELETE CASCADE,
  faction_id  TEXT NOT NULL REFERENCES game_factions(id) ON DELETE CASCADE,
  read_at_ms  INTEGER,
  PRIMARY KEY (message_id, faction_id)
);

-- Append-only event log. Every significant game event writes one row here.
-- This is the artifact players keep at end of match; UI is the chronicle viewer.
CREATE TABLE chronicle_entries (
  id                 TEXT PRIMARY KEY,
  game_id            TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  tick_number        INTEGER NOT NULL,
  kind               TEXT NOT NULL,         -- 'treaty_signed'|'treaty_broken'|'declaration'|'senate_vote'|
                                            -- 'battle'|'body_claimed'|'body_developed'|'ship_built'|
                                            -- 'ship_destroyed'|'faction_eliminated'|'tech_completed'|
                                            -- 'victory'|'game_started'|'game_ended'
  actor_faction_id   TEXT REFERENCES game_factions(id),
  target_faction_id  TEXT REFERENCES game_factions(id),
  body_id            TEXT REFERENCES game_bodies(id),
  ship_id            TEXT REFERENCES game_ships(id),
  payload            TEXT NOT NULL DEFAULT '{}',  -- JSON; freeform per kind
  visibility         TEXT NOT NULL DEFAULT 'public',  -- 'public' | JSON array of faction ids
  created_at_ms      INTEGER NOT NULL
);

CREATE INDEX idx_chronicle_game_tick ON chronicle_entries(game_id, tick_number, id);
CREATE INDEX idx_chronicle_kind ON chronicle_entries(game_id, kind);

-- ============================================================================
-- SECTION 8 — Orders, snapshots, reserved v2
-- ============================================================================

-- Catch-all for cross-cutting orders that don't fit a single domain table.
-- Most orders are NOT here — committing a maneuver is a node status flip,
-- queuing a build is a row in game_body_build_queue, voting is a row in
-- senate_votes. Use this only for actions that don't have a natural home.
CREATE TABLE pending_orders (
  id              TEXT PRIMARY KEY,
  game_id         TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  faction_id      TEXT NOT NULL REFERENCES game_factions(id) ON DELETE CASCADE,
  kind            TEXT NOT NULL,             -- 'sigint_scan'|'signed_declaration'|'custom'
  payload         TEXT NOT NULL DEFAULT '{}',
  submitted_at_ms INTEGER NOT NULL,
  target_tick     INTEGER NOT NULL,          -- the tick at which this is resolved
  status          TEXT NOT NULL DEFAULT 'pending', -- 'pending'|'applied'|'rejected'|'cancelled'
  applied_at_tick INTEGER,
  rejection_reason TEXT
);

CREATE INDEX idx_orders_target_tick ON pending_orders(game_id, target_tick, status);

-- Reserved for v2 standing-orders engine. Schema is defined now so the v2
-- migration is additive. No worker code should read/write this table in v1.
CREATE TABLE standing_orders (
  id              TEXT PRIMARY KEY,
  game_id         TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  faction_id      TEXT NOT NULL REFERENCES game_factions(id) ON DELETE CASCADE,
  trigger_kind    TEXT NOT NULL,
  trigger_payload TEXT NOT NULL DEFAULT '{}',
  action_kind     TEXT NOT NULL,
  action_payload  TEXT NOT NULL DEFAULT '{}',
  enabled         INTEGER NOT NULL DEFAULT 1,
  created_at_tick INTEGER NOT NULL,
  last_fired_tick INTEGER
);

CREATE INDEX idx_standing_orders_faction ON standing_orders(game_id, faction_id, enabled);

-- Per-tick snapshot for rollback / chronicle replay. JSON blob; lossy and
-- not authoritative. The relational rows are the source of truth.
CREATE TABLE game_snapshots (
  game_id        TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  tick_number    INTEGER NOT NULL,
  state_blob     TEXT NOT NULL,             -- JSON dump of derived per-faction views
  bytes          INTEGER NOT NULL,          -- length of state_blob; for storage telemetry
  created_at_ms  INTEGER NOT NULL,
  PRIMARY KEY (game_id, tick_number)
);

-- ============================================================================
-- END
-- ============================================================================
` },
  { name: "0004_senate_effects.sql", sql: `-- ============================================================================
-- Orbital — Senate Effects (v1)
-- ============================================================================
--
-- Adds the deferred-application table for senate slider laws. When a senate
-- proposal passes, the resolver inserts a row here with the slider id, the
-- chosen value, and the active tick window. Other systems (tick processor,
-- build cost calc, fuel yield, combat) read this table to compute the
-- effective slider value for a given (game_id, slider_id, current_tick).
--
-- The slider catalog itself (id, label, range, default) lives in worker
-- code (\`src/senate.js\`); this table holds only the per-game active overrides.
-- ============================================================================

CREATE TABLE senate_effects (
  id                 TEXT PRIMARY KEY,
  game_id            TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  slider_id          TEXT NOT NULL,
  value              REAL NOT NULL,
  proposal_id        TEXT REFERENCES senate_proposals(id) ON DELETE SET NULL,
  active_from_tick   INTEGER NOT NULL,
  active_until_tick  INTEGER NOT NULL,
  created_at_tick    INTEGER NOT NULL,
  created_at_ms      INTEGER NOT NULL
);

-- Most-recent active effect lookup: "for game G, slider S, at tick T, what's
-- the effect row where active_from_tick <= T < active_until_tick?".
CREATE INDEX idx_senate_effects_lookup
  ON senate_effects(game_id, slider_id, active_until_tick, active_from_tick);

CREATE INDEX idx_senate_effects_game ON senate_effects(game_id);
` },
  { name: "0005_empire_identity_and_starter_fleet.sql", sql: `-- Pre-game empire identity (set in lobby, carried into the game).
-- empire_name overrides the rotating-default faction name; bio is freeform
-- player-authored flavor text shown in the faction roster / diplomacy UI.
ALTER TABLE room_members ADD COLUMN empire_name TEXT;
ALTER TABLE room_members ADD COLUMN bio TEXT;

-- Bio carried through to the in-game faction record so it survives
-- after the lobby row could in principle be cleared.
ALTER TABLE game_factions ADD COLUMN bio TEXT;
` },
  { name: "0006_trade_offers.sql", sql: `-- ============================================================================
-- Orbital — Trade Offers (Civ/Stellaris-style diplomacy negotiation)
-- ============================================================================
--
-- Design notes:
--
-- 1. trade_offers vs treaties. The existing treaties table (0003) stores
--    finalized, signed agreements. trade_offers stores the back-and-forth
--    negotiation that precedes a treaty: A offers X for Y, B counters with
--    Y' for X, A accepts. When an offer is accepted, resource transfers
--    happen atomically AND any agreed pacts create rows in treaties.
--
-- 2. Counter-offer chains. A counter creates a NEW row that points at its
--    predecessor via parent_offer_id. The predecessor flips to 'countered'.
--    Walking back through parent_offer_id reconstructs the negotiation
--    history for the UI.
--
-- 3. Resource payload uses the four server-side faction resources
--    (metal/fuel/gold/science) directly. The client maps these to its
--    own display labels.
--
-- 4. Pacts. offer_pacts and request_pacts are JSON arrays of treaty kinds
--    ('nap', 'defense_pact', 'intel_share') that the side offering them
--    will sign if the trade is accepted. Empty array = no pacts offered.
--
-- 5. Visibility. An offer is visible to its proposer and its responder
--    only, plus optionally to spectators (not implemented in v1).
-- ============================================================================

CREATE TABLE trade_offers (
  id                    TEXT PRIMARY KEY,
  game_id               TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  proposer_faction_id   TEXT NOT NULL REFERENCES game_factions(id) ON DELETE CASCADE,
  responder_faction_id  TEXT NOT NULL REFERENCES game_factions(id) ON DELETE CASCADE,
  status                TEXT NOT NULL DEFAULT 'open',
    -- 'open'      : awaiting responder action
    -- 'accepted'  : responder accepted; resources & pacts applied
    -- 'declined'  : responder declined
    -- 'cancelled' : proposer withdrew before action
    -- 'countered' : responder made a counter-offer; superseded by child

  -- Resources offered BY proposer TO responder (proposer is paying).
  offer_metal           INTEGER NOT NULL DEFAULT 0,
  offer_fuel            INTEGER NOT NULL DEFAULT 0,
  offer_gold            INTEGER NOT NULL DEFAULT 0,
  offer_science         INTEGER NOT NULL DEFAULT 0,

  -- Resources requested BY proposer FROM responder (responder pays if accepted).
  request_metal         INTEGER NOT NULL DEFAULT 0,
  request_fuel          INTEGER NOT NULL DEFAULT 0,
  request_gold          INTEGER NOT NULL DEFAULT 0,
  request_science       INTEGER NOT NULL DEFAULT 0,

  -- Pacts that proposer offers to sign / requests responder to sign.
  -- JSON array of treaty kind strings, e.g. '["nap","intel_share"]'.
  offer_pacts           TEXT NOT NULL DEFAULT '[]',
  request_pacts         TEXT NOT NULL DEFAULT '[]',

  -- Counter-offer linkage. Walk parent_offer_id back to the original draft.
  parent_offer_id       TEXT REFERENCES trade_offers(id),

  -- Optional short note attached to the offer.
  note                  TEXT,

  created_at_tick       INTEGER NOT NULL,
  created_at_ms         INTEGER NOT NULL,
  resolved_at_ms        INTEGER,
  resolved_by_faction_id TEXT REFERENCES game_factions(id)
);

CREATE INDEX idx_trades_game_status ON trade_offers(game_id, status);
CREATE INDEX idx_trades_responder   ON trade_offers(responder_faction_id, status);
CREATE INDEX idx_trades_proposer    ON trade_offers(proposer_faction_id, status);
CREATE INDEX idx_trades_parent      ON trade_offers(parent_offer_id);
` },
  { name: "0007_rooms_invite_password.sql", sql: `-- Add invite codes and optional passwords to rooms.
-- invite_code: short URL-safe random string for "join by code" flow.
-- password_hash: NULL = open room; otherwise pbkdf2$... matches the
--   same format as users.password_hash (verifyPassword in worker/auth.js).

ALTER TABLE rooms ADD COLUMN invite_code TEXT;
ALTER TABLE rooms ADD COLUMN password_hash TEXT;

CREATE UNIQUE INDEX idx_rooms_invite_code ON rooms(invite_code) WHERE invite_code IS NOT NULL;
` },
  { name: "0008_starting_body.sql", sql: `-- Per-member chosen starting body. References a template id from the
-- worker's BODY_CATALOG (e.g. 'inara', 'verda', 'rust'). Null means
-- auto-assign at game start (the legacy behavior).
ALTER TABLE room_members ADD COLUMN chosen_starting_body TEXT;
` },
  { name: "0009_ship_combat.sql", sql: `-- Combat state on each ship row. Damage and HP mirror the client's
-- src/game/shipClasses.ts so server resolution stays balanced with
-- the player's intuition. damage_per_tick is the auto-fire rate at
-- a body shared with a hostile faction. status already exists; we
-- repurpose 'destroyed' (was reserved) once hp falls to zero.

ALTER TABLE game_ships ADD COLUMN hp REAL NOT NULL DEFAULT 100;
ALTER TABLE game_ships ADD COLUMN hp_max REAL NOT NULL DEFAULT 100;
ALTER TABLE game_ships ADD COLUMN damage_per_tick REAL NOT NULL DEFAULT 0;
` },
  { name: "0010_game_settlements.sql", sql: `-- Cities + orbital stations mirrored to D1 so the multiplayer canvas
-- can paint them server-authoritatively (and so the tick resolver can
-- harvest yields into settlement stockpiles).
--
-- type = 'city' has surface_angle (radians around body's surface).
-- type = 'station' has orbit_* elements (Keplerian orbit around body).
-- The columns the wrong type doesn't need are simply NULL.

CREATE TABLE game_settlements (
  id                  TEXT PRIMARY KEY,
  game_id             TEXT NOT NULL REFERENCES games(id) ON DELETE CASCADE,
  body_id             TEXT NOT NULL REFERENCES game_bodies(id) ON DELETE CASCADE,
  owner_faction_id    TEXT NOT NULL REFERENCES game_factions(id) ON DELETE CASCADE,
  type                TEXT NOT NULL,          -- 'city' | 'station'
  name                TEXT NOT NULL,
  hp                  REAL NOT NULL,
  hp_max              REAL NOT NULL,
  population          INTEGER NOT NULL DEFAULT 1,
  -- surface placement (city) or orbit (station)
  surface_angle       REAL,
  orbit_rp            REAL,
  orbit_ra            REAL,
  orbit_omega         REAL,
  orbit_m0            REAL,
  orbit_epoch         REAL,
  -- per-settlement stockpile (matches game_factions resource columns)
  stockpile_metal     INTEGER NOT NULL DEFAULT 0,
  stockpile_fuel      INTEGER NOT NULL DEFAULT 0,
  stockpile_gold      INTEGER NOT NULL DEFAULT 0,
  stockpile_science   INTEGER NOT NULL DEFAULT 0,
  -- lifecycle
  created_at_tick     INTEGER NOT NULL,
  last_growth_tick    INTEGER,
  last_harvest_tick   INTEGER,
  last_combat_tick    INTEGER,
  destroyed_at_tick   INTEGER
);

CREATE INDEX idx_settlements_game ON game_settlements(game_id);
CREATE INDEX idx_settlements_body ON game_settlements(body_id);
CREATE INDEX idx_settlements_owner ON game_settlements(owner_faction_id);
` },
  { name: "0011_node_arrival_at_tick.sql", sql: `-- Track the predicted Hohmann arrival tick on a maneuver node so the
-- tick resolver can separate "fired" from "arrived". Used to keep
-- in-flight ships visible (and animatable) on the canvas between
-- scheduled_t (departure burn) and arrival_at_tick (insertion burn).
-- NULL means the node hasn't fired yet, or it predates this migration.

ALTER TABLE game_ship_nodes ADD COLUMN arrival_at_tick INTEGER;
` },
  { name: "0012_faction_tech_level.sql", sql: `-- Add a level counter to faction_techs so the server can track infinite
-- Stellaris-style repeatables. The original schema only carried a
-- 'researching' / 'completed' status with no notion of how many times the
-- tech had been advanced. The level column reaches >0 once the first
-- buy-up has happened; status flips between researching/completed for the
-- current-in-progress tier (unused for instant-research v1, kept for the
-- future progress-bar model).

ALTER TABLE faction_techs ADD COLUMN level INTEGER NOT NULL DEFAULT 0;
` },
  { name: "0013_turn_based_mode.sql", sql: `-- Turn-Based Mode (MP, prototype).
--
-- Adds two game-level config columns + a per-faction commit ledger. When
-- a game has \`turn_based_enabled = 1\`, the Room DO's wall-clock alarm
-- stops auto-advancing the tick; instead the tick batch fires from
-- POST /api/games/:gameId/turn/commit once every faction has committed
-- the current turn.
--
-- The \`current_turn_number\` lives on \`games\` so a player's commit ledger
-- entry maps unambiguously back to "which turn this was for", even if
-- two players double-click in the same millisecond. After a successful
-- batch the worker increments \`current_turn_number\` and clears any
-- now-stale \`game_turn_commits\` rows.

ALTER TABLE games ADD COLUMN turn_based_enabled INTEGER NOT NULL DEFAULT 0;
ALTER TABLE games ADD COLUMN ticks_per_turn INTEGER NOT NULL DEFAULT 20;
ALTER TABLE games ADD COLUMN current_turn_number INTEGER NOT NULL DEFAULT 0;

-- One row per (game, faction, turn) pair recording when that faction
-- declared themselves ready to advance. Composite PK doubles as the
-- "already committed?" idempotency guard so a double-tap on the COMMIT
-- TURN button can't double-fire the batch.
CREATE TABLE IF NOT EXISTS game_turn_commits (
  game_id         TEXT    NOT NULL,
  faction_id      TEXT    NOT NULL,
  turn_number     INTEGER NOT NULL,
  committed_at_ms INTEGER NOT NULL,
  PRIMARY KEY (game_id, faction_id, turn_number)
);

CREATE INDEX IF NOT EXISTS idx_turn_commits_game_turn
  ON game_turn_commits(game_id, turn_number);
` },
  { name: "0014_settlement_collectors.sql", sql: `-- Collector network endpoint flag for settlements.
--
-- A collector is a logistics endpoint that lets stockpile drain to the
-- empire pool. Without one, every settlement piles resources locally
-- with nowhere to land. Capitals start with one (set in
-- worker/factions.js seedGameWorld); every other has to be built via
-- POST /api/games/:gameId/settlements/:settlementId/collector.
--
-- Tracked tick-of-construction is informational only — surfaces in the
-- BodyInspector as "built T+123". NULL on the free capital collector
-- so the UI can distinguish "starter" from "built-by-the-player."

ALTER TABLE game_settlements ADD COLUMN has_collector INTEGER NOT NULL DEFAULT 0;
ALTER TABLE game_settlements ADD COLUMN collector_built_tick INTEGER;
` },
  { name: "0015_settlement_buildings.sql", sql: `-- Settlement upgrade buildings (forge / mint / lab / weapons / shipyard).
--
-- The client has full UI for queueing per-settlement building upgrades
-- and a per-tick completion loop. The server was missing the schema +
-- endpoints entirely, so any MP build was wiped by the next /state poll
-- (same failure mode as the collector flag pre-0014).
--
-- Schema decision: JSON columns rather than join tables. Both blobs are
-- small (max 5 keys for buildings, single object for the order) and
-- they're always read together with the settlement row. A join table
-- would be cleaner but mean two extra queries per /state response.
--
--   buildings_json     {"forge": 2, "mint": 0, "lab": 1, ...}
--                      Missing key or 0 = not built.
--
--   building_order_json
--     {"kind": "forge", "target_level": 3,
--      "start_tick": 100, "complete_tick": 120}
--     NULL when nothing is in flight. One concurrent upgrade per
--     settlement — players have to spread their economy.

ALTER TABLE game_settlements ADD COLUMN buildings_json TEXT;
ALTER TABLE game_settlements ADD COLUMN building_order_json TEXT;
` },
  { name: "0016_trade_routes.sql", sql: `-- Trade routes (MP).
--
-- A trade route is a recurring freighter ferry between an origin
-- settlement and a destination collector. The Room DO alarm
-- auto-pilots the freighter: pick up at origin → fly to dest → drop
-- off → fly back → repeat until cancelled. If the freighter is
-- destroyed mid-route, the cargo is captured by the killer's pool
-- (piracy, handled in the combat block of resolveTick).
--
-- Columns mirror the client TradeRoute type. Server uses metal/gold
-- column names; the client maps to ore/credits at the deserialization
-- boundary (same convention as game_settlements.stockpile_*).
--
-- One active route per ship. If a player creates a second route for
-- the same freighter we replace the existing one (UI guard already
-- prevents this; the server still validates).

CREATE TABLE game_trade_routes (
  id                TEXT PRIMARY KEY,
  game_id           TEXT NOT NULL,
  owner_faction_id  TEXT NOT NULL,
  ship_id           TEXT NOT NULL,
  origin_body_id    TEXT NOT NULL,
  dest_body_id      TEXT NOT NULL,
  status            TEXT NOT NULL DEFAULT 'returning',
                    -- 'outbound'  = heading toward dest (cargo full)
                    -- 'returning' = heading toward origin (cargo empty)
                    -- 'paused'    = player paused; auto-pilot skips
  cargo_fuel        REAL NOT NULL DEFAULT 0,
  cargo_metal       REAL NOT NULL DEFAULT 0,
  cargo_gold        REAL NOT NULL DEFAULT 0,
  cargo_science     REAL NOT NULL DEFAULT 0,
  created_at_tick   INTEGER NOT NULL,
  cancelled_at_tick INTEGER
);

CREATE INDEX idx_trade_routes_game ON game_trade_routes(game_id, cancelled_at_tick);
CREATE UNIQUE INDEX idx_trade_routes_ship_active
  ON game_trade_routes(ship_id) WHERE cancelled_at_tick IS NULL;
` },
  { name: "0017_force_finish_bezier_transfers.sql", sql: `-- Force-finish all in-flight legacy Bezier transfers.
--
-- Phase 6 of the Bezier→Torch migration. The game's transfer model
-- changed from precomputed Hohmann-Bezier curves to a constant-thrust
-- (torch) brachistochrone integrated tick-by-tick. The new client
-- ignores legacy ship.transfer / ship.pendingTransfer fields and
-- drives ships via ship.transit instead.
--
-- Per the deploy plan (Q3 option B from the original migration spec):
-- any maneuver node that's currently committed-but-not-fired OR
-- in_transit at the moment this migration runs gets force-finished.
-- The ship is teleported into a parking orbit around the target body,
-- the node is marked 'cancelled', and any subsequent post-Bezier code
-- path that touched ship.transfer becomes a no-op.
--
-- Without this migration, active multiplayer games at deploy time
-- would silently lose their in-flight transfers (the new client
-- doesn't read those rows anymore) and players would see ships
-- frozen at their departure body forever.

-- Step 1: park ships sitting on an in-flight transfer at their
-- destination body. The ship's parent_body_id swaps to the target,
-- orbit elements reset to a clean low-altitude circular orbit, and
-- epoch is bumped to current_tick so the new orbit is "fresh."
--
-- D1 (SQLite) supports correlated subqueries in UPDATE — we use one
-- per column rather than a JOIN-update (which it doesn't support).
-- The CASE on b.radius pulls a sensible parking altitude (1.5×
-- body radius) when the body row exists; falls back to 6 game units.
UPDATE game_ships
SET
  parent_body_id = (
    SELECT n.target_body_id
    FROM game_ship_nodes n
    WHERE n.ship_id = game_ships.id
      AND n.status IN ('committed', 'in_transit')
      AND n.target_body_id IS NOT NULL
    LIMIT 1
  ),
  orbit_rp = (
    SELECT COALESCE(b.radius, 4) * 1.5
    FROM game_ship_nodes n
    LEFT JOIN game_bodies b ON b.id = n.target_body_id AND b.game_id = n.game_id
    WHERE n.ship_id = game_ships.id
      AND n.status IN ('committed', 'in_transit')
      AND n.target_body_id IS NOT NULL
    LIMIT 1
  ),
  orbit_ra = (
    SELECT COALESCE(b.radius, 4) * 1.5
    FROM game_ship_nodes n
    LEFT JOIN game_bodies b ON b.id = n.target_body_id AND b.game_id = n.game_id
    WHERE n.ship_id = game_ships.id
      AND n.status IN ('committed', 'in_transit')
      AND n.target_body_id IS NOT NULL
    LIMIT 1
  ),
  orbit_omega = 0,
  orbit_m0 = 0,
  orbit_direction = 1,
  orbit_epoch = (
    SELECT g.current_tick
    FROM games g
    WHERE g.id = game_ships.game_id
  )
WHERE id IN (
  SELECT DISTINCT n.ship_id
  FROM game_ship_nodes n
  WHERE n.status IN ('committed', 'in_transit')
    AND n.target_body_id IS NOT NULL
);

-- Step 2: cancel every committed/in_transit transfer node so the
-- alarm doesn't try to re-fire or arrive-process them. We deliberately
-- DON'T delete the rows so the chronicle/history still has a record;
-- the alarm code already skips status='cancelled'.
UPDATE game_ship_nodes
SET status = 'cancelled'
WHERE status IN ('committed', 'in_transit');

-- Add a faction-level engineG column so the torch executor (both
-- client and any future server-side torch integration) can scale
-- trip times by engine research. Default matches DEFAULT_ENGINE_G
-- in src/physics/torchTransfer.ts (0.05g — research-level-0 baseline).
ALTER TABLE game_factions ADD COLUMN engine_g REAL DEFAULT 0.05;
` },
  { name: "0018_dyson_sphere.sql", sql: `-- ============================================================================
-- Orbital — Dyson Sphere megaproject (Engineering Victory)
-- ============================================================================
--
-- One sphere per match. The faction that lays the foundation at a Sol-orbit
-- station becomes the controller. Per tick, every parked freighter the
-- controller owns at Sol drains a fixed quota from their empire pool and
-- contributes it to the sphere. Completing the sphere (hp >= max_hp)
-- triggers Engineering Victory.
--
-- Damage: the sphere absorbs damage routed through its foundation station
-- (see worker/room.js Dyson damage block in resolveTick). Damage reduces
-- hp and proportionally scales the accumulated resources so the progress
-- bar stays coherent. hp=0 collapses the sphere; the foundation slot
-- reopens for the next builder.
--
-- The state lives as nullable columns on the games row so we don't need a
-- separate table for a single megaproject per match. Worker code reads:
--   dyson_controller_faction_id IS NULL  → no sphere yet, slot open
--   ELSE                                  → sphere active, columns populated
-- ============================================================================

ALTER TABLE games ADD COLUMN dyson_controller_faction_id TEXT REFERENCES game_factions(id) ON DELETE SET NULL;
ALTER TABLE games ADD COLUMN dyson_foundation_settlement_id TEXT REFERENCES game_settlements(id) ON DELETE SET NULL;
ALTER TABLE games ADD COLUMN dyson_started_at_tick INTEGER;
ALTER TABLE games ADD COLUMN dyson_acc_fuel    INTEGER NOT NULL DEFAULT 0;
ALTER TABLE games ADD COLUMN dyson_acc_ore     INTEGER NOT NULL DEFAULT 0;
ALTER TABLE games ADD COLUMN dyson_acc_credits INTEGER NOT NULL DEFAULT 0;
ALTER TABLE games ADD COLUMN dyson_acc_science INTEGER NOT NULL DEFAULT 0;
ALTER TABLE games ADD COLUMN dyson_target_fuel    INTEGER NOT NULL DEFAULT 0;
ALTER TABLE games ADD COLUMN dyson_target_ore     INTEGER NOT NULL DEFAULT 0;
ALTER TABLE games ADD COLUMN dyson_target_credits INTEGER NOT NULL DEFAULT 0;
ALTER TABLE games ADD COLUMN dyson_target_science INTEGER NOT NULL DEFAULT 0;
ALTER TABLE games ADD COLUMN dyson_hp     INTEGER NOT NULL DEFAULT 0;
ALTER TABLE games ADD COLUMN dyson_max_hp INTEGER NOT NULL DEFAULT 0;

CREATE INDEX idx_games_dyson_controller ON games(dyson_controller_faction_id);
` },
  { name: "0019_dyson_damage_tracking.sql", sql: `-- ============================================================================
-- Orbital — Dyson Sphere damage-delta tracking
-- ============================================================================
--
-- Phase B shipped the sphere with collapse-on-foundation-destruction as the
-- only server-side loss vector. To let combat damage actually contest a
-- sphere in MP, the server tick processor needs to know how much HP the
-- foundation station lost since the last tick. We track that as a single
-- "last seen" column on the games row: each tick, tickDysonSphere reads
-- the foundation's current HP, compares to last_seen, applies the delta
-- to the sphere proportionally, then writes current HP back into the
-- column for next tick. NULL means "not initialized yet" — first read
-- after foundation-laying seeds it without applying damage.
-- ============================================================================

ALTER TABLE games ADD COLUMN dyson_station_last_hp INTEGER;
` },
  { name: "0020_ship_veterancy.sql", sql: `-- Ship veterancy + combat history (matches src/game/combat.ts + types.ts).
--
-- Every confirmed ship kill grants the killer hull +1 rank. Each rank
-- gives +1% damage output and +1% effective max HP. Stacks
-- multiplicatively with the faction-level Weapons/Armor tech mods.
--
-- \`combat_history\` is a JSON blob holding the last 20 kills as
-- ShipKillRecord[]: { tick, targetName, targetClass, atBodyId }.
-- Stored as TEXT (sqlite JSON1 is available but the worker code
-- treats it as plain JSON.parse on read, JSON.stringify on write).
-- Capped client- and server-side so the column stays small.
--
-- Both columns are nullable / defaulted so existing rows backfill
-- cleanly without a migration write — fresh hulls and pre-veterancy
-- saves both read as rank=0 / history=[].

ALTER TABLE game_ships ADD COLUMN rank INTEGER NOT NULL DEFAULT 0;
ALTER TABLE game_ships ADD COLUMN combat_history TEXT;
` },
];
